        MERGE  TBT_CM_REQ_REL_BZ_PART A
        USING (SELECT #{CM_REQ_ID} AS CM_REQ_ID
        			,#{BZ_PART_ID} AS BZ_PART_ID


              )  B
        ON (
        	A.CM_REQ_ID = B.CM_REQ_ID
        	AND A.BZ_PART_ID = B.BZ_PART_ID
        )
        WHEN MATCHED THEN
        UPDATE SET
			 DEL_FLAG   = #{DEL_FLAG}
			,UPDATE_DATE= SYSDATE
        WHEN NOT MATCHED THEN
        INSERT (
			 CM_REQ_ID
			,BZ_PART_ID
			,DEL_FLAG
			,INSERT_DATE
        ) VALUES (
			 #{CM_REQ_ID}
			,#{BZ_PART_ID}
			,#{DEL_FLAG}
			,SYSDATE
        )

        MERGE  TBT_CM_REQ_D2 A
        USING (SELECT #{CM_REQ_ID} AS CM_REQ_ID
        		,#{REC_NUM} REC_NUM

              )  B
        ON (
        	A.CM_REQ_ID = B.CM_REQ_ID
        	AND A.REC_NUM = B.REC_NUM

